def positivt_heltal(inmatning):
  """Tar reda på om en inmatning är ett postivit heltal
  Inparametrar: inmatning
  Returvärde: True/False (bool)"""
  try:
    inmatning = int(inmatning)
    if inmatning < 0:
      return False
    else:
  	  return True
  except ValueError:
    return False

def läs_tal_från_fil(filnamn):
  """ Läser ifrån en fil och returnerar en lista av postiva heltal
        Inparameter: filnamn (str)
        Returvärde:  resultat (list<Int>)
    """
  infil = open(filnamn, "r")
  resultat = []
  for rad in infil:
    rad = rad.strip()
    if positivt_heltal(rad):
      resultat.append(int(rad))
    else:
      print(rad, "är inte ett postivt heltal!")
  infil.close()
  return resultat

def huvudfunktion():
  resultat = läs_tal_från_fil("tal.txt")
  print("\nAlla positiva heltal från filen:")
  for tal in resultat:
    print(tal)

huvudfunktion()
